// LESSON: Reference Page 1 - Synlighet, final, static.
// You will learn: Protect state with private, final fields, and shared static members.
class Prog2Reference422 {
  // EXEMPEL 1: private skyddar falt och public ger kontrollerad atkomst.
  static class Account {
    private int balance;
    public void deposit(int amount) {
      if (amount > 0) { balance += amount; }
    }
    public int balance() { return balance; }
  }
  // EXEMPEL 2: final markerar att referensen eller vardet inte ska omtilldelas.
  static class Course {
    private final String code;
    Course(String code) { this.code = code; }
    String code() { return code; }
  }
  // EXEMPEL 3: static hor till klassen och delas av alla objekt.
  static class Ticket {
    static final int VAT_PERCENT = 12;
    private static int created;
    Ticket() { created++; }
    static int createdCount() { return created; }
  }
}
